1	// Unit tests for the Apify client wrapper.
2	//
3	// Replace `globalThis.fetch` with a spy, then assert each wrapper function
4	// constructs the correct URL (actor slug + token + waitForFinish) and POST
5	// body (actor input shape per docs/tech-architecture.md §3b / §3c).
6	//
7	// Run: deno test --allow-env supabase/functions/_shared/apify.test.ts
8	
9	import {
10	  assertEquals,
11	  assertRejects,
12	} from "jsr:@std/assert@1";
13	
14	import {
15	  runInstagramDetails,
16	  runInstagramPosts,
17	  runTikTokProfile,
18	} from "./apify.ts";
19	
20	type Captured = { url: string; init: RequestInit };
21	
22	function installFetchSpy(
23	  response: Record<string, unknown>,
24	  init: ResponseInit = { status: 201 },
25	): { captured: Captured[]; restore: () => void } {
26	  const original = globalThis.fetch;
27	  const captured: Captured[] = [];
28	  globalThis.fetch = ((input: string | URL | Request, reqInit?: RequestInit) => {
29	    const url = typeof input === "string"
30	      ? input
31	      : input instanceof URL
32	      ? input.toString()
33	      : input.url;
34	    captured.push({ url, init: reqInit ?? {} });
35	    return Promise.resolve(
36	      new Response(JSON.stringify(response), {
37	        status: init.status ?? 201,
38	        headers: { "content-type": "application/json" },
39	      }),
40	    );
41	    // deno-lint-ignore no-explicit-any -- fetch has many overloads; the spy matches the subset we use
42	  }) as any;
43	  return { captured, restore: () => { globalThis.fetch = original; } };
44	}
45	
46	function stubRunResponse() {
47	  return {
48	    data: {
49	      id: "run_abc123",
50	      defaultDatasetId: "ds_xyz789",
51	      status: "SUCCEEDED",
52	    },
53	  };
54	}
55	
56	function setApifyKey(value: string | null) {
57	  if (value === null) Deno.env.delete("APIFY_KEY");
58	  else Deno.env.set("APIFY_KEY", value);
59	}
60	
61	Deno.test("runTikTokProfile builds the tiktok actor run request", async () => {
62	  setApifyKey("test-token");
63	  const { captured, restore } = installFetchSpy(stubRunResponse());
64	  try {
65	    const result = await runTikTokProfile("charlidamelio");
66	
67	    assertEquals(captured.length, 1);
68	    const url = new URL(captured[0].url);
69	    assertEquals(url.origin + url.pathname,
70	      "https://api.apify.com/v2/acts/clockworks~tiktok-scraper/runs");
71	    assertEquals(url.searchParams.get("token"), "test-token");
72	    assertEquals(url.searchParams.get("waitForFinish"), "60");
73	
74	    assertEquals(captured[0].init.method, "POST");
75	    const headers = new Headers(captured[0].init.headers as HeadersInit);
76	    assertEquals(headers.get("content-type"), "application/json");
77	
78	    const body = JSON.parse(captured[0].init.body as string);
79	    assertEquals(body, {
80	      profiles: ["charlidamelio"],
81	      resultsPerPage: 10,
82	      profileScrapeSections: ["videos"],
83	      profileSorting: "latest",
84	      excludePinnedPosts: true,
85	      shouldDownloadVideos: false,
86	      shouldDownloadCovers: false,
87	    });
88	
89	    assertEquals(result, {
90	      runId: "run_abc123",
91	      datasetId: "ds_xyz789",
92	      status: "SUCCEEDED",
93	    });
94	  } finally {
95	    restore();
96	  }
97	});
